import{_ as s,c as i,o as n,aj as l}from"./chunks/framework.VtnL2jmu.js";const g=JSON.parse('{"title":"MySQL 交互神器 mycli 实战笔记","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/MySQL 交互神器mycli 实战笔记.md","filePath":"Linux/MySQL 交互神器mycli 实战笔记.md"}'),e={name:"Linux/MySQL 交互神器mycli 实战笔记.md"};function t(o,a,r,c,p,h){return n(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="mysql-交互神器-mycli-实战笔记" tabindex="-1">MySQL 交互神器 mycli 实战笔记 <a class="header-anchor" href="#mysql-交互神器-mycli-实战笔记" aria-label="Permalink to “MySQL 交互神器 mycli 实战笔记”">​</a></h1><blockquote><p>📊 告别黑白终端</p></blockquote><h3 id="💡-为什么需要-mycli" tabindex="-1">💡 为什么需要 mycli？ <a class="header-anchor" href="#💡-为什么需要-mycli" aria-label="Permalink to “💡 为什么需要 mycli？”">​</a></h3><p>原生的 MySQL 客户端就像在记事本里写代码，而 <strong>mycli</strong> 就像是给数据库装上了 <strong>IDE</strong>。它支持：</p><ul><li><strong>智能补全</strong>：自动提示关键字、表名、字段名。</li><li><strong>语法高亮</strong>：SQL 不再是一坨白字。</li><li><strong>排版美化</strong>：自动处理超宽表格。</li></ul><hr><h3 id="🛠-安装篇-依然首选隔离环境" tabindex="-1">🛠 安装篇：依然首选隔离环境 <a class="header-anchor" href="#🛠-安装篇-依然首选隔离环境" aria-label="Permalink to “🛠 安装篇：依然首选隔离环境”">​</a></h3><p>由于 mycli 依赖较多 Python 库，为了避免和系统环境打架，继续使用 <code>pipx</code> 安装：</p><div class="language-Bash"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 隔离安装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pipx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mycli</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. (可选) 如果需要连接加密方式较旧的数据库，可能需要加额外依赖</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># pipx inject mycli cryptography</span></span></code></pre></div><hr><h3 id="🚀-核心秘籍-提效进阶技巧" tabindex="-1">🚀 核心秘籍：提效进阶技巧 <a class="header-anchor" href="#🚀-核心秘籍-提效进阶技巧" aria-label="Permalink to “🚀 核心秘籍：提效进阶技巧”">​</a></h3><h4 id="_1-垂直显示-最实用" tabindex="-1">1. 垂直显示 (最实用！) <a class="header-anchor" href="#_1-垂直显示-最实用" aria-label="Permalink to “1. 垂直显示 (最实用！)”">​</a></h4><p>当你的表字段太多（比如 Spring Boot 常见的 <code>sys_user</code> 表有 20 多个字段），屏幕横向显示会乱成一团。</p><ul><li><strong>操作</strong>：在 SQL 结尾加 <code>\\G</code> 或者在结果出来后按 <strong><code>F3</code></strong>。</li><li><strong>效果</strong>：每一行数据都会以“字段: 值”的垂直列表显示，看数据清爽无比。</li></ul><h4 id="_2-sql-收藏夹-拯救健忘症" tabindex="-1">2. SQL 收藏夹 (拯救健忘症) <a class="header-anchor" href="#_2-sql-收藏夹-拯救健忘症" aria-label="Permalink to “2. SQL 收藏夹 (拯救健忘症)”">​</a></h4><p>有些复杂的统计 SQL 记不住？</p><ul><li><strong>保存</strong>：执行 <code>\\fs 别名 你的复杂SQL</code></li><li><strong>调用</strong>：执行 <code>\\f 别名</code> 即可再次运行。</li></ul><h4 id="_3-配置文件定制化-myclirc" tabindex="-1">3. 配置文件定制化 (<code>~/.myclirc</code>) <a class="header-anchor" href="#_3-配置文件定制化-myclirc" aria-label="Permalink to “3. 配置文件定制化 (~/.myclirc)”">​</a></h4><p>建议修改以下几项，让它更符合你的习惯：</p><p>Ini, TOML</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 修改配置文件</span></span>
<span class="line"><span>nano ~/.myclirc</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 建议配置：</span></span>
<span class="line"><span>multi_line = True         # 开启多行模式（按分号才执行）</span></span>
<span class="line"><span>syntax_style = paraiso-dark # 换个酷炫的主题</span></span>
<span class="line"><span>smart_completion = True   # 开启智能补全</span></span></code></pre></div><hr><h3 id="🧪-spring-boot-开发实战场景" tabindex="-1">🧪 Spring Boot 开发实战场景 <a class="header-anchor" href="#🧪-spring-boot-开发实战场景" aria-label="Permalink to “🧪 Spring Boot 开发实战场景”">​</a></h3><p>在开发你的 <code>fast-web-tmp</code> 项目时，可以这样配合：</p><ul><li><p><strong>数据校验</strong>：</p><p>用 HTTPie 发送 POST 请求后，顺手在 mycli 里：</p><p><code>SELECT * FROM users ORDER BY create_time DESC LIMIT 1;</code></p><p>确认数据是否按预期落库。</p></li><li><p><strong>结构变更</strong>：</p><p>直接在 mycli 里敲 <code>ALTER TABLE</code>，补全功能会帮你快速定位那些记不清拼写的字段名。</p></li><li><p><strong>采纳整行提示</strong>：</p><p><strong>方向右键 (<code>→</code>)</strong>：这是最常用的方法。按一下右箭头，整行灰色文字就会变成实体文字。</p><p><strong><code>Ctrl + E</code></strong>：这也是 Unix 终端常用的快捷键，意为“移动到行尾”，在 <code>mycli</code> 中同样可以采纳建议。</p></li></ul><hr><h3 id="⚠️-避坑提醒" tabindex="-1">⚠️ 避坑提醒 <a class="header-anchor" href="#⚠️-避坑提醒" aria-label="Permalink to “⚠️ 避坑提醒”">​</a></h3><ol><li><strong>认证报错</strong>：如果遇到 <code>Authentication plugin &#39;caching_sha2_password&#39; cannot be loaded</code>，这是 MySQL 8.0 的默认认证问题。 <ul><li><strong>解决</strong>：登录 MySQL 后执行 <code>ALTER USER &#39;root&#39;@&#39;localhost&#39; IDENTIFIED WITH mysql_native_password BY &#39;你的密码&#39;;</code>。</li></ul></li><li><strong>路径缓存</strong>：如果你之前装过旧版，记得还是那招：<code>hash -d mycli</code>。</li></ol>`,28)])])}const y=s(e,[["render",t]]);export{g as __pageData,y as default};
